values
('21-gun-salute', '21 Gun Salute', 'Shenanigans', 'To obtain the 21 Gun Salute bar, a student must drink 21 glasses of any assortment of beverages available at any of the cafeterias, using the glasses they provide at the caf. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/21_Gun_Salute', 'hard', 400, array['Hard']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('21st-century', '21st Century', 'Shenanigans', 'To complete this bar, a person must complete 21 Gun Salute followed by Century Club in the same day.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/21st_Century', 'legendary', 475, array['Legendary']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('21st-century-wizard', '21st Century Wizard', 'Shenanigans', 'Complete 21 Gun Salute, Century Club, and Wizard within 24 hours. The 24 hours do not need to be the same calendar day.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/21st_Century_Wizard', 'legendary', 500, array['Legendary']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('40-beers', '40 Beers', 'Shenanigans', '40 Beers involves drinking 40 beers in a period of 24 hours. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/40_Beers', 'legendary', 500, array['Legendary']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('advance-to-goodes', 'Advance To Goodes', 'Shenanigans', 'In a group of 3+ in formal attire (suits and ties) or GPAs (still with ties), must challenge passing commies to, start, and finish a game of Monopoly... See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Advance_To_Goodes', 'medium', 225, array['Medium']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('beer-belt', 'Beer Belt', 'Shenanigans', 'You have 12 hours to attach every beer can that you finish to your beer belt (a strand of tape [with the sticky side facing outwards]). See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Beer_Belt', 'hard', 425, array['Hard']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('beerio-kart', 'Beerio Kart', 'Shenanigans', 'Beerio Kart (also known as Grand Pre, KUI, Don''t Drink and Drive, and others) is a set of drinking games to be played alongside Mario Kart.There are many... See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Beerio_Kart', 'medium', 200, array['Medium']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('beerlin-wall', 'Beerlin Wall', 'Shenanigans', 'Completely cover your Don''s door in beer cans while they are in their room.Note that all alcohol must be drunk in one night, but can be drunk by... See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Beerlin_Wall', 'hard', 350, array['Hard']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('brew-master', 'Brew Master', 'Shenanigans', 'Brew Master bar is similar to Tap Master only it involves making either beer or wine (or moonshine we don''t discriminate) in your rez room and then consuming it. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Brew_Master', 'hard', 375, array['Hard']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('century-club', 'Century Club', 'Shenanigans', 'To obtain this bar, a student must drink one shot of beer every minute for one hundred consecutive minutes. Vomiting during the attempt will nullify the attempt.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Century_Club', 'hard', 425, array['Hard']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('clark-decagon', 'Clark Decagaon', 'Shenanigans', 'Take 10 shots of hard liquor or finish a pitcher in 10 minutes at Ritual at Clark Hall Pub. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Clark_Decagon', 'legendary', 450, array['Legendary']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('cuffed', 'Cuffed', 'Shenanigans', 'It''s cuffing season baby! See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Cuffed', 'hard', 400, array['Hard']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('drink-to-the-future', 'Drink to the Future', 'Shenanigans', 'Drink to the Future is a drinking bar. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Drink_to_the_Future', 'medium', 225, array['Medium']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('dusted', 'DUSTED', 'Shenanigans', 'This stands for "Drink an Unsuspecting Small Town Establishment Dry". See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/DUSTED', 'hard', 400, array['Hard']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('fellowship', 'Fellowship', 'Shenanigans', 'The premise of the bar is to download all three of the Lord of the Rings: Extended Editions, and watch them consecutively (it takes approx. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Fellowship', 'legendary', 450, array['Legendary']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('frost-week', 'Frost Week', 'Shenanigans', 'Frost Week is for those brave enough to face the elements in the most epic of clothing, The GPA.To obtain "Frost Week" one must don sandals (add socks... See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Frost_Week', 'hard', 425, array['Hard']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('god-of-the-sea', 'God of the Sea', 'Shenanigans', 'Participants must create a beer can trident, standing as tall as themselves (Like a wizard staff with to branches coming off of the main tower.) Estimated 16-18 tallboys.for... See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/God_Of_The_Sea', 'legendary', 450, array['Legendary']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('heineken-hammer', 'Heineken Hammer', 'Shenanigans', 'The participant must finish a Heineken Mini Keg (5L, approx. 14-15 bottles). They then attach the keg to a sturdy handle (baseball ball, 2×4, hockey stick, etc.) to create said "Heineken Hammer."', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Heineken_Hammer', 'legendary', 450, array['Legendary']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('hero-of-canton', 'Hero of Canton', 'Shenanigans', 'In a similar manner to every other drinking bar involving sitting in one position for twelve hours drinking; Hero of Canton requires that you steadily drink your way through Joss Whedon''s Firefly collection. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Hero_of_Canton', 'hard', 400, array['Hard']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('home-for-a-rest', 'Home For a Rest', 'Shenanigans', 'AKA: Home For A Rekt. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Home_For_A_Rest', 'legendary', 450, array['Legendary']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('ilcbo', 'ILCBO', 'Shenanigans', 'For ILCBO, a small group of 4-5 people must alternate taking shots at every single group room in the ILC (one per group room). as of the 2017-2018 academic year there are 39 rooms.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/ILCBO', 'legendary', 450, array['Legendary']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('isengard', 'Isengard', 'Shenanigans', 'Isengard is a variation of wizard. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Isengard', 'hard', 400, array['Hard']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('iron-curtain', 'Iron Curtain', 'Shenanigans', 'You must build an "Iron Curtain" that separates Lenny East from Lenny West, along the first floor lobby. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Iron_Curtain', 'hard', 350, array['Hard']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('iron-throne', 'Iron Throne', 'Shenanigans', 'This bar is based on HBO''s emmy-winning show A Game of Thrones. Recommended group size is 7-10 people. Starting from Season 1 Episode 1 and ending at episode 9 "Baelor" (at Ned Starks exit)---.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Iron_Throne', 'medium', 225, array['Medium']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('last-man-standing', 'Last Man Standing', 'Shenanigans', 'Also known as Last Woman Standing and Last One Standing. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Last_Man_Standing', 'hard', 425, array['Hard']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('lumberjack', 'Lumberjack', 'Shenanigans', 'Starting October 1st or earlier, do not shave your beard or cut your hair (minor trimming allowed) for the rest of the semester. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Lumberjack', 'medium', 250, array['Medium']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('naked-knights', 'Naked Knights', 'Shenanigans', 'Naked Knights involves streaking (usually around the city block where you are) while wearing only a medieval Knight helmet and shoes. (One can make the helmet out of beer)', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Naked_Knights', 'legendary', 500, array['Legendary']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('no-hablo', 'No Hablo', 'Shenanigans', 'For the iLliTEraTe and English impaired people who failed the English proficiency test. If you "fail" the test because you skipped it in order to get this bar, you don''t get the bar, you''re just an idiot.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/No_Hablo', 'easy', 75, array['Easy']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('party-star', 'Party Star', 'Shenanigans', 'Play an entire 50 turn game of Mario Party (must be 4 players, no CPUs). See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Party_Star', 'medium', 200, array['Medium']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('raiders', 'Raiders', 'Shenanigans', 'Similar to Fellowship and Drink to the Future. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Raiders', 'medium', 200, array['Medium']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('ritual', 'Ritual', 'Shenanigans', 'Attend Ritual at Clark Hall Pub 10 times in a row within one semester (does not carry over Winter break) or 14 times in total within an academic year (carries over Winter break). See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Ritual', 'medium', 250, array['Medium']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('rocky-road', 'Rocky Road', 'Shenanigans', 'Taking a tub of ice cream from Leonard cafeteria or Ban Righ caf and run it to Miller Hall. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Rocky_Road', 'easy', 100, array['Easy']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('slam-it-home', 'Slam It Home', 'Shenanigans', 'Get together with your fellow Queen''s engineers and do a jacket slam at your hometown university.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Slam_It_Home', 'easy', 100, array['Easy']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('smashed-bros', 'Smashed Bros', 'Shenanigans', 'In Super Smash Bros, each player is given 100 lives. Every time your character dies, you must take a shot of beer. Traditonally this is done in SSB Melee on the map Final Destination.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Smashed_Bros', 'medium', 225, array['Medium']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('smooth-criminal', 'Smooth Criminal', 'Shenanigans', 'Recieve a level 3 documentation in residence without getting kicked out of res. Getting this on purpose or on the last day/week is just plain stupid.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Smooth_Criminal', 'legendary', 450, array['Legendary']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('squeaky-clean', 'Squeaky Clean', 'Shenanigans', 'To obtain the bar "Squeaky Clean", one must take a shower in every named residence building. Squeaky Clean must be completed in the span of 7 hours.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Squeaky_Clean', 'hard', 400, array['Hard']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('tap-master', 'Tap Master', 'Shenanigans', 'Host a rez kegger. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Tap_Master', 'legendary', 500, array['Legendary']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('tir-na-nog', 'Tir Na Nog', 'Shenanigans', 'A bar created for those who frequent Tír nan Óg (an Irish pub downtown) thursday nights. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Tir_Na_Nog', 'medium', 175, array['Medium']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('totem', 'Totem', 'Shenanigans', 'The idea is similar to Wizard. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Totem', 'legendary', 500, array['Legendary']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('white-wizard', 'White Wizard', 'Shenanigans', 'White Wizard is obtained by completing Wizard during Fellowship . Mandatory to choose Gandalf as your character.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/White_Wizard', 'legendary', 500, array['Legendary']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true),
('wizard', 'Wizard', 'Shenanigans', 'Within a 12 hour time frame, you must drink your height in beers. See the wiki for full requirements.', 'Refer to the linked wiki page for the full traditional requirements before organizing this bar.', 'https://gpabars.fandom.com/wiki/Wizard', 'legendary', 450, array['Legendary']::text[], array['Clark Hall', 'Residence Common Area', 'Other']::text[], true, true)
on conflict (id) do update set
